import{_ as a,c as t,o as i,aj as r}from"./chunks/framework.guNMSiFm.js";const p=JSON.parse('{"title":"Release Readiness","description":"","frontmatter":{},"headers":[],"relativePath":"guide/best-practices/release-readiness.md","filePath":"guide/best-practices/release-readiness.md","lastUpdated":1777621302000}'),n={name:"guide/best-practices/release-readiness.md"};function o(s,e,l,c,d,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="release-readiness" tabindex="-1">Release Readiness <a class="header-anchor" href="#release-readiness" aria-label="Permalink to &quot;Release Readiness&quot;">​</a></h1><p>Before promoting an Iroha application or network change, prove the behavior in the smallest environment that can expose the relevant risk, then move through shared testnet and production gates deliberately.</p><h2 id="localnet-gate" tabindex="-1">Localnet Gate <a class="header-anchor" href="#localnet-gate" aria-label="Permalink to &quot;Localnet Gate&quot;">​</a></h2><ul><li>Launch a disposable local network with the same Iroha track and the closest practical validator count.</li><li>Run unit tests for transaction builders, query parsing, rejection handling, and config loading.</li><li>Exercise the smallest successful read and write paths through the same SDK or CLI shape the application will use later.</li><li>Capture expected transaction hashes, statuses, events, and state reads in test artifacts.</li></ul><p>See <a href="/iroha-2-docs/get-started/launch-iroha-2.html">Launch Iroha 3</a> and <a href="/iroha-2-docs/guide/tutorials/">SDK Tutorials</a>.</p><h2 id="shared-testnet-gate" tabindex="-1">Shared Testnet Gate <a class="header-anchor" href="#shared-testnet-gate" aria-label="Permalink to &quot;Shared Testnet Gate&quot;">​</a></h2><ul><li>Use Taira or another shared testnet for endpoint behavior, fees, account funding, latency, and operational rehearsals.</li><li>Keep live testnet writes opt-in so ordinary test runs do not depend on network availability or spend testnet funds.</li><li>Verify signer funding, fee asset metadata, authority permissions, and expected state before submitting each live test transaction.</li><li>Wait for a terminal status, then verify the resulting state with a read-only query.</li></ul><p>See <a href="/iroha-2-docs/get-started/sora-nexus-dataspaces.html">Build on SORA 3: Taira and Minamoto</a>.</p><h2 id="mainnet-or-production-gate" tabindex="-1">Mainnet or Production Gate <a class="header-anchor" href="#mainnet-or-production-gate" aria-label="Permalink to &quot;Mainnet or Production Gate&quot;">​</a></h2><ul><li>Use separate production signers, funding, domains, and config paths. Do not promote testnet keys or faucet assumptions.</li><li>Confirm SDK, CLI, peer, and network compatibility with the <a href="/iroha-2-docs/reference/compatibility-matrix.html">Compatibility Matrix</a>.</li><li>Review permissions, fee sponsorship, rate limits, monitoring, backup status, and rollback criteria before the release window.</li><li>Require a written transaction or migration plan for high-impact writes.</li></ul><h2 id="rollback-and-recovery" tabindex="-1">Rollback and Recovery <a class="header-anchor" href="#rollback-and-recovery" aria-label="Permalink to &quot;Rollback and Recovery&quot;">​</a></h2><ul><li>Define which changes can be rolled back by code deploy, which require an on-chain transaction, and which cannot be undone directly.</li><li>For on-chain data changes, prepare compensating transactions or migration scripts before the first production write.</li><li>For network changes, keep the previous binary, config bundle, signed genesis, and operational runbook available during the release.</li><li>Set a decision point for aborting the rollout based on objective signals such as rejection rate, queue growth, latency, or peer health.</li></ul><h2 id="final-checklist" tabindex="-1">Final Checklist <a class="header-anchor" href="#final-checklist" aria-label="Permalink to &quot;Final Checklist&quot;">​</a></h2><ul><li>Configuration is environment-specific and does not contain test-only secrets.</li><li>Transaction retry behavior is idempotent or explicitly bounded.</li><li>The application can distinguish rejection, expiry, timeout, and endpoint availability failures.</li><li>Monitoring covers throughput, latency, queue depth, rejections, view changes, and relevant business events.</li><li>Operators have runbooks for expected failure modes.</li><li>Security review covered key custody, permissions, network exposure, and automation authority.</li></ul>',14)])])}const f=a(n,[["render",o]]);export{p as __pageData,f as default};
